package javaday10;

public class smallestthreenumber {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int a=20,b=30,c=200;
		
		if(a<b&&a<c)
		{
			System.out.println("a is smallest");
		}
		else if(b<a&&b<c)
		{
			System.out.println("b is smallest");
		}
		else
		{
			System.out.println("c is smallest");
		}

	}

}
